import {
  mkdir,
  readFile,
  readdir,
  rename,
  rm,
  writeFile,
} from 'node:fs/promises';
import path from 'node:path';

export const GENERATED_PAGE_MARKER =
  '{/* GENERATED BY scripts/generate-paper-pages.mjs. DO NOT EDIT. */}';
const LEGACY_GENERATED_PAGE_MARKER =
  '<!-- GENERATED BY scripts/generate-paper-pages.mjs. DO NOT EDIT. -->';

const VIEW_PAGES = [
  {
    relativePath: path.join('all', 'index.mdx'),
    title: 'All Papers',
    description: 'Every verified paper record in the LLM Optimizer Atlas.',
    view: 'all',
  },
  {
    relativePath: path.join('by-research-track', 'index.mdx'),
    title: 'Papers by Research Track',
    description: 'Verified paper records grouped by the atlas research tracks.',
    view: 'by-track',
  },
  {
    relativePath: path.join('by-publication-status', 'index.mdx'),
    title: 'Papers by Publication Status',
    description: 'Verified paper records grouped as published, accepted, or preprint.',
    view: 'by-status',
  },
  {
    relativePath: path.join('by-year', 'index.mdx'),
    title: 'Papers by Year',
    description: 'Verified paper records grouped by source year.',
    view: 'by-year',
  },
];

function yamlString(value) {
  return JSON.stringify(value);
}

function viewPageSource(page) {
  return `---
title: ${yamlString(page.title)}
description: ${yamlString(page.description)}
---

${GENERATED_PAGE_MARKER}

import PaperCollection from '../../../../../components/PaperCollection.astro';

<PaperCollection view=${yamlString(page.view)} />
`;
}

function detailPageSource(paper) {
  return `---
title: ${yamlString(paper.title)}
description: ${yamlString('Generated paper record for ' + paper.title + '.')}
---

${GENERATED_PAGE_MARKER}

import PaperDetail from '../../../../../../components/PaperDetail.astro';

<PaperDetail paperId=${yamlString(paper.id)} />
`;
}

export function createGeneratedPaperPages(papers) {
  const pages = new Map();

  for (const page of VIEW_PAGES) {
    pages.set(page.relativePath, viewPageSource(page));
  }

  for (const paper of papers) {
    pages.set(
      path.join('papers', paper.id, 'index.mdx'),
      detailPageSource(paper),
    );
  }

  return pages;
}

async function collectFiles(directory) {
  let entries;
  try {
    entries = await readdir(directory, { withFileTypes: true });
  } catch (error) {
    if (error?.code === 'ENOENT') {
      return [];
    }
    throw error;
  }

  const files = [];
  for (const entry of entries) {
    const target = path.join(directory, entry.name);
    if (entry.isDirectory()) {
      files.push(...(await collectFiles(target)));
    } else {
      files.push(target);
    }
  }
  return files;
}

async function readExistingSource(file) {
  try {
    return await readFile(file, 'utf8');
  } catch (error) {
    if (error?.code === 'ENOENT') {
      return null;
    }
    throw error;
  }
}

function isOwnedGeneratedPage(source) {
  const normalizedSource = normalizeLineEndings(source);
  return [GENERATED_PAGE_MARKER, LEGACY_GENERATED_PAGE_MARKER].some((marker) =>
    normalizedSource.includes('\n' + marker + '\n'),
  );
}

function normalizeLineEndings(source) {
  return source.replace(/\r\n/g, '\n');
}

function resolveContainedTarget(outputDirectory, relativePath) {
  const root = path.resolve(outputDirectory);
  const target = path.resolve(root, relativePath);
  if (target !== root && !target.startsWith(root + path.sep)) {
    throw new Error(
      'Generated page path escapes the output directory: ' + relativePath,
    );
  }
  return target;
}

async function writeFileAtomically(target, source) {
  const temporaryPath =
    target + '.' + process.pid + '.' + Date.now() + '.generated.tmp';
  try {
    await writeFile(temporaryPath, source, 'utf8');
    await rename(temporaryPath, target);
  } catch (error) {
    await rm(temporaryPath, { force: true });
    throw error;
  }
}

export async function synchronizeGeneratedPaperPages(
  outputDirectory,
  pages,
  { check = false } = {},
) {
  const expectedRelativePaths = new Set(pages.keys());
  const existingFiles = await collectFiles(outputDirectory);
  const issues = [];
  const staleOwnedFiles = [];

  for (const file of existingFiles) {
    const relativePath = path.relative(outputDirectory, file);
    const source = await readFile(file, 'utf8');
    if (!isOwnedGeneratedPage(source)) {
      issues.push(
        relativePath +
          ': unowned file is inside the generated directory; move it before generation',
      );
    } else if (!expectedRelativePaths.has(relativePath)) {
      staleOwnedFiles.push(file);
      if (check) {
        issues.push(relativePath + ': stale generated page');
      }
    }
  }

  for (const [relativePath, expectedSource] of pages) {
    const target = resolveContainedTarget(outputDirectory, relativePath);
    const actualSource = await readExistingSource(target);
    if (actualSource === null) {
      if (check) {
        issues.push(relativePath + ': generated page is missing');
      }
    } else if (
      normalizeLineEndings(actualSource) !==
        normalizeLineEndings(expectedSource) &&
      check
    ) {
      issues.push(relativePath + ': generated page is out of date');
    }
  }

  if (issues.length > 0) {
    return { ok: false, issues, written: 0, removed: 0 };
  }

  if (check) {
    return { ok: true, issues: [], written: 0, removed: 0 };
  }

  await mkdir(outputDirectory, { recursive: true });
  for (const file of staleOwnedFiles) {
    await rm(file, { force: true });
  }

  let written = 0;
  for (const [relativePath, source] of pages) {
    const target = resolveContainedTarget(outputDirectory, relativePath);
    const actualSource = await readExistingSource(target);
    if (
      actualSource !== null &&
      normalizeLineEndings(actualSource) === normalizeLineEndings(source)
    ) {
      continue;
    }
    await mkdir(path.dirname(target), { recursive: true });
    await writeFileAtomically(target, source);
    written += 1;
  }

  return {
    ok: true,
    issues: [],
    written,
    removed: staleOwnedFiles.length,
  };
}
